SET GLOBAL slow_query_log = 'ON';
SET GLOBAL long_query_time = 0.1;
SET GLOBAL log_queries_not_using_indexes = 'ON';

Create indexes that target checkout-specific patterns:
-- Target the actual bottlenecks
